    public Client(long l, String hiba, String mail, String casa, String number) {
    }
}

ALTER TABLE livraison
    ADD CONSTRAINT fk_livraison_client
        FOREIGN KEY (client_id) REFERENCES client(id),

    ADD CONSTRAINT fk_livraison_chauffeur
        FOREIGN KEY (chauffeur_id) REFERENCES chauffeur(id),

    ADD CONSTRAINT fk_livraison_vehicule
        FOREIGN KEY (vehicule_id) REFERENCES vehicule(id);

ALTER TABLE vehicule
    MODIFY statut VARCHAR(30) NOT NULL DEFAULT 'DISPONIBLE';

ALTER TABLE chauffeur
    MODIFY disponible BOOLEAN NOT NULL DEFAULT TRUE;

ALTER TABLE livraison
    MODIFY statut VARCHAR(30) NOT NULL DEFAULT 'ENATTENTE';

ALTER TABLE vehicule
    ADD CONSTRAINT chk_capacite_positive CHECK (capacite > 0);

ALTER TABLE livraison
    ADD CONSTRAINT fk_livraison_client
        FOREIGN KEY (client_id) REFERENCES client(id);

ALTER TABLE livraison
    ADD CONSTRAINT fk_livraison_chauffeur
        FOREIGN KEY (chauffeur_id) REFERENCES chauffeur(id);

ALTER TABLE livraison
    ADD CONSTRAINT fk_livraison_vehicule
        FOREIGN KEY (vehicule_id) REFERENCES vehicule(id);

ALTER TABLE vehicule
    MODIFY statut VARCHAR(30) NOT NULL DEFAULT 'DISPONIBLE';

ALTER TABLE chauffeur
    MODIFY disponible BOOLEAN NOT NULL DEFAULT TRUE;

ALTER TABLE livraison
    MODIFY statut VARCHAR(30) NOT NULL DEFAULT 'ENATTENTE';

ALTER TABLE vehicule
    ADD CONSTRAINT chk_capacite_positive CHECK (capacite > 0);

package com.fleetflow.Entity;


import com.fleetflow.enums.StatutVehicule;
import jakarta.persistence.*;
import lombok.*;

import java.util.List;

@Data
@AllArgsConstructor
@NoArgsConstructor
@Builder
@Entity
@Table(name = "vehicule")
public class Vehicule {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    @Column(unique = true)
    private String matricule;
    private String type;
    private Integer capacite;
    @Enumerated(EnumType.STRING)
    private StatutVehicule statut;

    @OneToMany(mappedBy = "vehicule",cascade = CascadeType.ALL)
    @ToString.Exclude
     private List<Livraison> livraisons;
}

package com.fleetflow.Entity;


import com.fleetflow.enums.StatutVehicule;
import jakarta.persistence.*;
import lombok.*;

import java.util.List;

@Data
@AllArgsConstructor
@NoArgsConstructor
@Builder
@Entity
@Table(name = "vehicule")
public class Vehicule {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    @Column(unique = true, nullable = false)
    private String matricule;
    @Column(nullable = false)
    private String type;
    @Column(nullable = false)
    private Integer capacite;
    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    private StatutVehicule statut;

    @OneToMany(mappedBy = "vehicule",cascade = CascadeType.ALL)
    @ToString.Exclude
     private List<Livraison> livraisons;
}

package com.fleetflow.Dto;

import com.fleetflow.enums.StatutVehicule;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;
import lombok.Data;

@Data
public class VehiculeDto {
    private Long id;
    @NotBlank(message = "Le matricul est obligatoire")
    private String matricule;
    @NotBlank(message = "Le type est obligatoire")
    private String type;
    @NotNull(message = "La capacite est obligatoire")
    private Double capacite;
    @NotNull(message = "Le statut est obligatoire")
    private StatutVehicule statut;
}

package com.fleetflow.Dto;

