package com.fleetflow.Service;

import com.fleetflow.Dto.VehiculeDto;
import com.fleetflow.Entity.Vehicule;
import com.fleetflow.Mapper.VehiculeMapper;
import com.fleetflow.Repository.VehiculeRepository;
import com.fleetflow.enums.StatutVehicule;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.util.Arrays;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class VehiculeServiceTest {

    @Mock
    private VehiculeRepository vehiculeRepository;

    @Mock
    private VehiculeMapper vehiculeMapper;

    @InjectMocks
    private VehiculeService vehiculeService;

    private Vehicule vehicule;
    private VehiculeDto vehiculeDto;

    @BeforeEach
    void setUp() {
        vehicule = new Vehicule();
        vehicule.setId(1L);
        vehicule.setMatricule("AB-123-CD");
        vehicule.setType("CAMION");
        vehicule.setCapacite(5000.0);
        vehicule.setStatut(StatutVehicule.DISPONIBLE);

        vehiculeDto = new VehiculeDto();
        vehiculeDto.setId(1L);
        vehiculeDto.setMatricule("AB-123-CD");
        vehiculeDto.setType("CAMION");
        vehiculeDto.setCapacite(5000.0);
        vehiculeDto.setStatut(StatutVehicule.DISPONIBLE);
    }

    //  Test : Lister les véhicules disponibles
    @Test
    void testListerVehiculesDisponibles() {
        // ARRANGE
        List<Vehicule> vehicules = Arrays.asList(vehicule);
        when(vehiculeRepository.findByStatut(StatutVehicule.DISPONIBLE)).thenReturn(vehicules);
        when(vehiculeMapper.toDto(vehicule)).thenReturn(vehiculeDto);

        // ACT
        List<VehiculeDto> resultat = vehiculeService.getVehiculesDisponible();

        // ASSERT
        assertNotNull(resultat);
        assertEquals(1, resultat.size());
        assertEquals(StatutVehicule.DISPONIBLE, resultat.get(0).getStatut());
        verify(vehiculeRepository, times(1)).findByStatut(StatutVehicule.DISPONIBLE);
    }

    //  Test : Ajouter un véhicule
    @Test
    void testAjouterVehicule() {
        // ARRANGE
        when(vehiculeMapper.toEntity(vehiculeDto)).thenReturn(vehicule);
        when(vehiculeRepository.save(vehicule)).thenReturn(vehicule);
        when(vehiculeMapper.toDto(vehicule)).thenReturn(vehiculeDto);

        // ACT
        VehiculeDto resultat = vehiculeService.addVehicule(vehiculeDto);

        // ASSERT
        assertNotNull(resultat);
        assertEquals("AB-123-CD", resultat.getMatricule());
        verify(vehiculeRepository, times(1)).save(vehicule);
    }

    //  Test : Chercher par capacité supérieure à une valeur
    @Test
    void testFindByCapaciteGreaterThan() {
        // ARRANGE
        List<Vehicule> vehicules = Arrays.asList(vehicule);
        when(vehiculeRepository.findByCapaciteGreaterThan(1000)).thenReturn(vehicules);
        when(vehiculeMapper.toDto(vehicule)).thenReturn(vehiculeDto);

        // ACT
        List<VehiculeDto> resultat = vehiculeService.getVehiculeCapaciteGreaterThan(1000);

        // ASSERT
        assertEquals(1, resultat.size());
        assertTrue(resultat.get(0).getCapacite() > 1000);
    }
}

